{
  "task_id": "DEV-011",
  "applicable_policies": [
    {
      "doc_id": "08_budget_management.md",
      "title": "XX证券预算管理办法",
      "effective_from": "2025-01-01",
      "reason": "现行有效的预算管理办法，发文字号XX证财规〔2025〕辛号。与费用报销制度共同构成费用控制依据（第五条）。所有被审核记录均在2025年1-3月，属于本办法有效期内。",
      "applicable_clauses": [
        {"clause_no": "第二条", "content": "各部门应在年度预算额度内发生费用", "applicability": "直接适用：要求部门在预算额度内发生费用"},
        {"clause_no": "第三条", "content": "部门费用累计使用达到年度预算额度的1.0倍后,原则上不得继续报销", "applicability": "直接适用：定义预算超限的阈值为预算额度的1.0倍"},
        {"clause_no": "第四条", "content": "因监管要求、客户服务或经营连续性确需超预算支出的,应履行专项审批", "applicability": "直接适用：超预算豁免条件为履行专项审批"}
      ]
    },
    {
      "doc_id": "01_expense_reimbursement_2025.md",
      "title": "XX证券费用报销管理办法(2025修订版)",
      "effective_from": "2025-01-01",
      "reason": "现行有效的费用报销制度，发文字号XX证财规〔2025〕甲号。第十四条明确自2025年1月1日起施行并废止2022版。所有被审核记录在2025年1-3月。",
      "applicable_clauses": [
        {"clause_no": "第十三条", "content": "部门年度预算不足时不得继续报销。预算使用达到预算额度的1.0倍后,确需发生的费用应履行专项审批", "applicability": "直接适用：与预算管理办法第二、三、四条一致，明确预算超限后必须专项审批"}
      ]
    }
  ],
  "excluded_policies": [
    {
      "doc_id": "02_expense_reimbursement_2022_deprecated.md",
      "title": "XX证券费用报销管理办法(2022版)",
      "exclusion_reason": "已废止。第一条明确仅作制度沿革留档。第四条明确审批金额已被后续制度替代。2025修订版第十四条明确自2025年1月1日起废止2022版。"
    }
  ],
  "policy_conflicts": [],
  "unresolved_items": []
}

